UPDATE detalle_ventas dv JOIN productos p1 ON dv.producto_id = p1.id JOIN (SELECT nombre, MIN(id) as min_id FROM productos GROUP BY nombre) p2 ON p1.nombre = p2.nombre SET dv.producto_id = p2.min_id; DELETE p1 FROM productos p1 JOIN (SELECT nombre, MIN(id) as min_id FROM productos GROUP BY nombre) p2 ON p1.nombre = p2.nombre AND p1.id > p2.min_id; ALTER TABLE productos ADD UNIQUE (nombre);  
